SELECT DISTINCT p.production_name, p.description
FROM productions p
JOIN production_nominees pn ON p.production_id = pn.production_id;

SELECT category_id, COUNT(nominee_id) AS number_of_nominees
FROM nominees
GROUP BY category_id;

SELECT name 
FROM nominees 
WHERE nominee_id = 1;

SELECT nominees.name, categories.category_name
FROM nominees
JOIN categories ON nominees.category_id = categories.category_id;

SELECT award_show_name, award_show_date
FROM award_shows
ORDER BY award_show_date DESC;

SELECT MAX(access_date)
FROM access_logs
WHERE user_id = 1;
